sql:
SELECT text_content
FROM text_data
WHERE split = 'validation';

SELECT platform, COUNT(*) AS text_count
FROM text_data
GROUP BY platform;

SELECT annotator_name
FROM annotators
ORDER BY annotator_name ASC;

SELECT MAX(accuracy) AS highest_accuracy
FROM annotator_performance
WHERE date = '2022-01-02';

external_knowledge:
External knowledge:

* Accuracy and F1 score are metrics used to evaluate the performance of annotators; 
* Ranking by accuracy and F1 score helps identify top performers; 
* Filtering results to a specific time period (January 2022) and limiting output to top results helps focus on relevant data.

sql:
SELECT annotator_name
FROM annotators
ORDER BY annotator_name;

SELECT COUNT(*) AS total_texts
FROM text_data
WHERE platform = 'Twitter' AND split = 'train';

SELECT label_name
FROM sexist_labels
WHERE label_id = 1;

external_knowledge:
; Annotators are considered confident when they assign a high value to the confidence_level column; 
; This query can help identify the overall reliability of annotators in labeling sexist texts; 
; The training dataset is a subset of the data used to train machine learning models.

